import java.io.*;

public class XSSSecureCode {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String userInput = reader.readLine();

        // Sanitize and escape user input to prevent XSS
        String sanitizedInput = sanitizeInput(userInput);

        System.out.println("Hello, " + sanitizedInput);
    }

    private static String sanitizeInput(String input) {
        // Replace potentially harmful characters with safe alternatives
        return input.replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("&", "&amp;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
